import json
import time
from dataclasses import dataclass, field
from typing import List, Dict, Optional, Callable
from collections import Counter
import hashlib
import math


@dataclass
class EvalResult:
    prompt: str
    response: str
    reference: Optional[str]
    metrics: Dict[str, float] = field(default_factory=dict)
    llm_judge_score: Optional[float] = None
    llm_judge_reasoning: Optional[str] = None
    human_score: Optional[float] = None
    latency_ms: float = 0.0
    tokens_used: int = 0
    cost_usd: float = 0.0


class GenAIEvaluator:
    """Comprehensive evaluation framework for generative AI systems."""

    def __init__(self, model_fn: Optional[Callable] = None):
        self.model_fn = model_fn
        self.results: List[EvalResult] = []

    def compute_bleu(self, reference: str, hypothesis: str, max_n: int = 4) -> float:
        """Compute BLEU score between reference and hypothesis."""
        ref_tokens = reference.lower().split()
        hyp_tokens = hypothesis.lower().split()

        if not hyp_tokens:
            return 0.0

        precisions = []
        for n in range(1, max_n + 1):
            ref_ngrams = Counter(self._get_ngrams(ref_tokens, n))
            hyp_ngrams = Counter(self._get_ngrams(hyp_tokens, n))
            clipped = sum(min(count, ref_ngrams[ng]) for ng, count in hyp_ngrams.items())
            total = sum(hyp_ngrams.values())
            precision = clipped / total if total > 0 else 0.0
            precisions.append(precision)

        if min(precisions) == 0:
            return 0.0

        geometric_mean = math.exp(sum(math.log(p + 1e-10) for p in precisions) / len(precisions))
        brevity_penalty = min(1.0, math.exp(1 - len(ref_tokens) / len(hyp_tokens)))
        return brevity_penalty * geometric_mean

    def compute_rouge_l(self, reference: str, hypothesis: str) -> float:
        """Compute ROUGE-L score using longest common subsequence."""
        ref_tokens = reference.lower().split()
        hyp_tokens = hypothesis.lower().split()
        lcs_length = self._lcs_length(ref_tokens, hyp_tokens)
        precision = lcs_length / len(hyp_tokens) if hyp_tokens else 0.0
        recall = lcs_length / len(ref_tokens) if ref_tokens else 0.0
        if precision + recall == 0:
            return 0.0
        return 2 * precision * recall / (precision + recall)

    def compute_bertscore_simple(self, reference: str, hypothesis: str) -> float:
        """Simplified semantic similarity score based on word overlap."""
        ref_words = set(reference.lower().split())
        hyp_words = set(hypothesis.lower().split())
        if not ref_words or not hyp_words:
            return 0.0
        intersection = ref_words & hyp_words
        precision = len(intersection) / len(hyp_words)
        recall = len(intersection) / len(ref_words)
        if precision + recall == 0:
            return 0.0
        return 2 * precision * recall / (precision + recall)

    def evaluate_single(self, prompt: str, response: str, reference: Optional[str] = None) -> EvalResult:
        """Evaluate a single prompt-response pair."""
        result = EvalResult(prompt=prompt, response=response, reference=reference)

        if reference:
            result.metrics["bleu"] = self.compute_bleu(reference, response)
            result.metrics["rouge_l"] = self.compute_rouge_l(reference, response)
            result.metrics["bertscore"] = self.compute_bertscore_simple(reference, response)

        result.metrics["length"] = len(response.split())
        result.metrics["contains_reference_words"] = (
            1.0 if reference and any(w in response.lower() for w in reference.lower().split()[:5]) else 0.0
        )

        return result

    def evaluate_batch(self, test_cases: List[Dict]) -> Dict:
        """Evaluate a batch of test cases and return aggregate metrics."""
        all_results = []
        for tc in test_cases:
            prompt = tc["prompt"]
            reference = tc.get("reference")
            response = self.model_fn(prompt) if self.model_fn else tc.get("response", "")
            result = self.evaluate_single(prompt, response, reference)
            all_results.append(result)

        self.results.extend(all_results)
        return self._aggregate_results(all_results)

    def llm_judge_evaluation(self, prompt: str, response: str, criteria: List[str] = None) -> Dict:
        """Generate a structured prompt for LLM-as-judge evaluation."""
        if criteria is None:
            criteria = ["helpfulness", "accuracy", "safety", "coherence"]

        judge_prompt = f"""You are an expert evaluator. Rate the following AI response on these criteria: {', '.join(criteria)}.

Prompt: {prompt}

Response: {response}

For each criterion, provide a score from 1-5 and a brief explanation.
Return JSON with format: {{"scores": {{criterion: score}}, "reasoning": {{criterion: explanation}}}}"""

        return {
            "judge_prompt": judge_prompt,
            "criteria": criteria,
        }

    def _aggregate_results(self, results: List[EvalResult]) -> Dict:
        """Aggregate evaluation results into summary statistics."""
        if not results:
            return {}

        metric_keys = results[0].metrics.keys()
        aggregated = {}
        for key in metric_keys:
            values = [r.metrics.get(key, 0) for r in results]
            aggregated[key] = {
                "mean": sum(values) / len(values),
                "min": min(values),
                "max": max(values),
            }

        aggregated["total_evaluations"] = len(results)
        return aggregated

    def _get_ngrams(self, tokens: List[str], n: int) -> List[str]:
        return [" ".join(tokens[i:i+n]) for i in range(len(tokens) - n + 1)]

    def _lcs_length(self, x: List[str], y: List[str]) -> int:
        m, n = len(x), len(y)
        dp = [[0] * (n + 1) for _ in range(m + 1)]
        for i in range(1, m + 1):
            for j in range(1, n + 1):
                if x[i-1] == y[j-1]:
                    dp[i][j] = dp[i-1][j-1] + 1
                else:
                    dp[i][j] = max(dp[i-1][j], dp[i][j-1])
        return dp[m][n]


# Example usage
if __name__ == "__main__":
    evaluator = GenAIEvaluator()

    test_cases = [
        {
            "prompt": "Explain what a neural network is",
            "response": "A neural network is a computing system inspired by biological brains.",
            "reference": "A neural network is a machine learning model inspired by the human brain."
        },
        {
            "prompt": "What is Python used for",
            "response": "Python is used for web development, data science, and AI.",
            "reference": "Python is a programming language used for web development, data science, and machine learning."
        }
    ]

    results = evaluator.evaluate_batch(test_cases)
    print("Evaluation Results:")
    print(json.dumps(results, indent=2))

    judge_prompt = evaluator.llm_judge_evaluation(
        prompt="Explain what a neural network is",
        response="A neural network is a computing system inspired by biological brains."
    )
    print("\nLLM Judge Prompt:")
    print(judge_prompt["judge_prompt"])
